import pygamedef create_buttons(width, height):    """    Create the timeframe and dark mode buttons.    """    button_width = 100    button_height = 35    button_gap = 10    buttons = {        "1 Day": pygame.Rect(            button_gap,            height - button_height - button_gap,            button_width,            button_height,        ),        "1 Week": pygame.Rect(            button_gap * 2 + button_width,            height - button_height - button_gap,            button_width,            button_height,        ),        "1 Month": pygame.Rect(            button_gap * 3 + button_width * 2,            height - button_height - button_gap,            button_width,            button_height,        ),        "1 Year": pygame.Rect(            button_gap * 4 + button_width * 3,            height - button_height - button_gap,            button_width,            button_height,        ),        "Max": pygame.Rect(            button_gap * 5 + button_width * 4,            height - button_height - button_gap,            button_width,            button_height,        ),        "Dark Mode": pygame.Rect(            button_gap * 6 + button_width * 5,            height - button_height - button_gap,            button_width + 25,            button_height,        ),    }    return buttonsdef draw_buttons(screen, buttons, button_color, text_color):    """    Draw the timeframe and dark mode buttons.    """    font = pygame.font.Font(None, 24)    for label, rect in buttons.items():        pygame.draw.rect(screen, button_color, rect, border_radius=5)        text = font.render(label, True, text_color)        text_rect = text.get_rect(center=rect.center)        screen.blit(text, text_rect)def draw_tooltip(screen, x, y, text, dark_mode):    """    Draw a tooltip showing date and price.    """    font = pygame.font.Font(None, 24)    tooltip_text_color = (255, 255, 255) if dark_mode else (0, 0, 0)    tooltip_background = (40, 40, 40) if dark_mode else (230, 230, 230)    text_surface = font.render(text, True, tooltip_text_color)    tooltip_rect = text_surface.get_rect(topleft=(x + 12, y + 12))    tooltip_rect.inflate_ip(12, 8)    pygame.draw.rect(screen, tooltip_background, tooltip_rect, border_radius=4)    screen.blit(text_surface, (tooltip_rect.x + 6, tooltip_rect.y + 4))